  ('heelevel3-53250add-moex-00216', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於行政法法源之敘述，下列何者正確？', '["緊急命令係取代或暫停法律之規範，故其不得作為行政法之法源", "法規命令規範事項雖屬行政機關內部事務，但仍可作為行政法之法源", "由立法院審議通過產生國內法律效力後，係屬行政法之法源", "行政規則在對人民權利有所限制時，才能例外作為行政法法源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00217', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '下列何者須有法律或有法律具體明確授權之依據始得為之？', '["補助國旅", "吊銷證照", "執行法律之細節性、技術性事項", "不涉及重大公益之給付行政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00218', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於訴訟紛爭之解決途徑，下列敘述何者錯誤？', '["政府機關採購物品之履約爭議，得向普通法院提起民事訴訟", "消費者向公營銀行貸款之履約爭議，得向普通法院提起民事訴訟", "不服台灣電力公司計收電費之通知，得向普通法院提起民事訴訟", "申請購買國民住宅，因資格不符而遭拒絕，得向普通法院提起民事訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
