  ('heelevel3-53250add-moex-00220', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於委託行使公權力之概念，下列敘述何者錯誤？', '["受託行使公權力之個人或團體，於委託範圍內，視為行政機關", "委託行使公權力得僅限於私經濟行政", "委託方式得以行政處分或行政契約為之", "行政機關得依法規將其權限之一部分，委託民間團體或個人辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
